column1:
cat <<'EOF'
## Deep-Merge Example

### Preset's scope config (system-explorer profile):
{
  :paths {
    :read ["/**"]
    :write []
    :deny ["**/.git/**", "**/.env"]
  }
  :bash-tools { ... }
  :org-roam-patterns { ... }
}

### Activities worktree-paths:
{
  :paths {
    :read ["/activity/worktrees/**"]
    :write ["/activity/worktrees/**"]
    :deny ["**/node_modules/**"]
  }
}

### Deep-merged result:
{
  :paths {
    :read ["/**", "/activity/worktrees/**"]  # Concatenated, deduplicated
    :write ["/activity/worktrees/**"]        # Activities added write access
    :deny ["**/.git/**", "**/.env", "**/node_modules/**"]  # Merged
  }
  :bash-tools { ... }  # Preserved from preset
  :org-roam-patterns { ... }  # Preserved from preset
}
EOF
